import { useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';

import constFlaskURL from '../../consts/constFlaskURL'

import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function EditSing() {
    const [name_sing, setName] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();
    const { id } = useParams();

    const handleLogout = async () => {
        setLoading(true);

        try 
        {
            const response = await constFlaskURL.post('/logout');

            if (response.status === 200) 
            {
                setTimeout(() => {
                    navigate('/login');
                }, 1000);
            }
        }
        catch (err) 
        {
            console.error('Logout error:', err);
        } 
        finally 
        {
            setLoading(false);
        }
    };

    const submitSing = async (e) => {
        e.preventDefault();
        setLoading(true);
        const sing = { name_sing };

        try {
            const add_sing = await constFlaskURL.post('/sings', sing);

            if (add_sing.status === 200){
                setName('');
                navigate('/sings');
            }
        } catch (error) {
            console.log(error);
        }
    };

    return (
        <div>
            <nav className="navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0">
                <div className="container-fluid py-2">
                    <Link className="navbar-brand fs-3 fw-bold" to="/main">roads_admin</Link>
                    <Link className="navbar-brand fs-3 fw-bold">
                        <button 
                            onClick={handleLogout} 
                                className="logout-button"
                                disabled={loading}
                            >
                            {loading ? (
                            <>
                                <span className="spinner"></span>
                                Выход...
                            </>
                            ) : 'Выйти'}
                        </button>
                    </Link>
                </div>
            </nav>
            <form className='container' onSubmit={submitSing}>
                <div className='mb-3'>
                    <lable className='form-label'>Название дорожного знака</lable>
                    <input 
                        type='text'
                        name='name_sing' 
                        value={name_sing.name_sing} 
                        onChange={(e) => setName(e.target.value)}
                        className='form-input'  
                        placeholder='Название дорожного знака'
                        required  
                    />
                </div>
                <button 
                    type='submit' 
                    className='btn btn-primary'
                >
                    Сохранить
                </button>
                <button 
                    type='submit' 
                    className='btn btn-danger' 
                    onClick={() => navigate('/sings')}
                >
                    Назад
                </button>
            </form>
        </div>
    )

};

export default EditSing;
